<script setup>
import {ref} from 'vue';import {useRouter} from 'vue-router';import {useAuthStore} from '../stores/auth';import {useCartStore} from '../stores/cart'
const props=defineProps({product:{type:Object,required:true}}),router=useRouter(),auth=useAuthStore(),cart=useCartStore(),busy=ref(false),message=ref('')
const money=value=>new Intl.NumberFormat('zh-TW',{style:'currency',currency:'TWD',maximumFractionDigits:0}).format(value||0),conditions={NEW:'全新',LIKE_NEW:'近全新',EXCELLENT:'優良',GOOD:'良好',FAIR:'可用'}
async function add(){if(!auth.isAuthenticated)return router.push({path:'/login',query:{redirect:router.currentRoute.value.fullPath}});busy.value=true;message.value='';try{await cart.add(props.product.id,1);message.value='已加入購物車'}catch(e){message.value=e.message}finally{busy.value=false}}
</script>
<template><article class="product-card"><RouterLink class="product-image" :to="`/products/${product.id}`"><img v-if="product.imageUrl" :src="product.imageUrl" :alt="product.productName"><span v-else>SECOND PHONE</span><em v-if="product.featured">精選</em></RouterLink><div class="product-card-body"><div class="product-meta"><span>{{product.brand}}</span><span>{{product.model}}</span></div><h3><RouterLink :to="`/products/${product.id}`">{{product.productName}}</RouterLink></h3><div class="product-tags"><span>{{product.storageCapacity||'容量未標示'}}</span><span>{{conditions[product.conditionLevel]||product.conditionLevel}}</span></div><div class="product-card-footer"><div><strong>{{money(product.price)}}</strong><small :class="product.availableStock>0?'text-success':'text-danger'">{{product.availableStock>0?`現貨 ${product.availableStock}`:'暫時缺貨'}}</small></div><RouterLink class="button button-primary button-small" :to="`/products/${product.id}`">查看詳情</RouterLink></div><button class="button button-secondary button-full" :disabled="busy||product.availableStock<=0" @click="add">{{busy?'加入中…':'加入購物車'}}</button><small v-if="message" class="inline-message">{{message}}</small></div></article></template>
